mapper.update:
UPDATE WH_PRESS
SET 
    PRS_NAME = #{PRS_NAME}

        , STORED_FILE_NM = #{STORED_FILE_NM}


        , PRS_PWD = CONCAT('*', UPPER(SHA1(UNHEX(SHA1(#{PRS_PWD})))))

WHERE PRS_ID = #{PRS_ID}

mapper.select:
SELECT CON_ID, CON_BODY, CREATED_DATE
FROM WH_STAR_CONTENT
WHERE CON_ID = #{CON_ID} AND PRS_ID = #{PRS_ID}
